package main

import (
	"fmt"
	"sync"
)

type Bank struct {
	accounts map[string]int
	mu       sync.RWMutex
}

func NewBank() *Bank {
	return &Bank{
		accounts: make(map[string]int),
	}
}

func (b *Bank) Deposit(account string, amount int) {
	b.mu.Lock()
	defer b.mu.Unlock()
	b.accounts[account] += amount
}

func (b *Bank) Withdraw(account string, amount int) bool {
	b.mu.Lock()
	defer b.mu.Unlock()
	if b.accounts[account] >= amount {
		b.accounts[account] -= amount
		return true
	}
	return false
}

func (b *Bank) Balance(account string) int {
	b.mu.RLock()
	defer b.mu.RUnlock()
	return b.accounts[account]
}

func main() {
	bank := NewBank()
	var wg sync.WaitGroup

	// Example usage
	wg.Add(3)
	go func() {
		defer wg.Done()
		bank.Deposit("Alice", 100)
	}()
	go func() {
		defer wg.Done()
		bank.Withdraw("Alice", 50)
	}()
	go func() {
		defer wg.Done()
		fmt.Println("Balance:", bank.Balance("Alice"))
	}()

	wg.Wait()
	fmt.Println("Final Balance:", bank.Balance("Alice"))
}